const fs = require('fs');

// Convert Excel date serial to JavaScript Date
function excelDateToJSDate(excelDate) {
  // Excel dates are days since January 1, 1900 (with 1900 leap year bug)
  const excelEpoch = new Date(1899, 11, 30); // December 30, 1899
  const jsDate = new Date(excelEpoch.getTime() + excelDate * 86400000);
  return jsDate;
}

// Format date as "Month Day, Year"
function formatDate(date) {
  const options = { year: 'numeric', month: 'long', day: 'numeric' };
  return date.toLocaleDateString('en-US', options);
}

// Read template
const template = fs.readFileSync('/job/tmp/template.html', 'utf-8');

// Convert Excel date 46082 to readable format
const leaseStartDate = excelDateToJSDate(46082);
const leaseStartFormatted = formatDate(leaseStartDate);

// Today's date
const today = new Date();
const todayFormatted = formatDate(today);

// Replace placeholders
let lease = template;
lease = lease.replace(/{{TENANT_NAME}}/g, 'Christian Lachausse, Christine Nisbett & Camden Andrade');
lease = lease.replace(/{{PROPERTY_ADDRESS}}/g, '111 E Main Street, Celina, TX 75009');
lease = lease.replace(/{{MONTHLY_RENT}}/g, '$1,800.00');
lease = lease.replace(/{{LEASE_START}}/g, leaseStartFormatted);
lease = lease.replace(/{{SECURITY_DEPOSIT}}/g, 'Tenant has paid a security deposit of $1,800.00, which will be held by Landlord and returned at the end of the tenancy, subject to deductions for damages beyond normal wear and tear.');
lease = lease.replace(/{{UTILITIES_SECTION}}/g, 'Tenant will be invoiced monthly for all utilities (water, electric, gas, etc.).');
lease = lease.replace(/{{CUSTOM_TERMS}}/g, 'Mowing of yard is included in the base rent and will be provided by Landlord.');
lease = lease.replace(/{{DATE}}/g, todayFormatted);
lease = lease.replace(/{{CONTACT_EMAIL}}/g, 'Sloan@tjmfuneral.com');
lease = lease.replace(/{{CONTACT_PHONE}}/g, '(972) 632-2787');

// Write rendered lease
fs.writeFileSync('/job/tmp/lease.html', lease);
console.log('Lease HTML generated successfully');
console.log('Lease start date:', leaseStartFormatted);
